/* About overlay */
.jiranimo-about-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(9, 30, 66, 0.54);
  z-index: 10001;
  display: flex;
  align-items: center;
  justify-content: center;
  animation: jiranimo-fade-in 0.15s ease;
}

@keyframes jiranimo-fade-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

.jiranimo-about-modal {
  position: relative;
  background: #fff;
  border-radius: 12px;
  padding: 32px;
  width: 480px;
  max-width: 92vw;
  max-height: 90vh;
  overflow-y: auto;
  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.35);
  color: #172b4d;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  animation: jiranimo-slide-up 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
}

@keyframes jiranimo-slide-up {
  from { transform: translateY(16px); opacity: 0; }
  to   { transform: translateY(0);    opacity: 1; }
}

.jiranimo-about-close {
  position: absolute;
  top: 14px; right: 14px;
  background: none;
  border: none;
  color: #6b778c;
  font-size: 18px;
  cursor: pointer;
  padding: 4px 8px;
  border-radius: 4px;
  line-height: 1;
}

.jiranimo-about-close:hover {
  background: #f4f5f7;
  color: #172b4d;
}

.jiranimo-about-header {
  text-align: center;
  padding-bottom: 20px;
  border-bottom: 1px solid #ebecf0;
  margin-bottom: 20px;
}

.jiranimo-about-logo {
  width: 48px;
  height: 48px;
  color: #0052cc;
  margin-bottom: 10px;
}

.jiranimo-about-header h2 {
  margin: 0 0 6px;
  font-size: 24px;
  font-weight: 700;
  color: #172b4d;
}

.jiranimo-about-tagline {
  margin: 0;
  font-size: 14px;
  color: #6b778c;
}

.jiranimo-about-body {
  font-size: 14px;
  line-height: 1.6;
}

.jiranimo-about-body > p {
  margin: 0 0 16px;
  color: #344563;
}

.jiranimo-about-section {
  margin-bottom: 18px;
}

.jiranimo-about-section h3 {
  margin: 0 0 8px;
  font-size: 12px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: #6b778c;
}

.jiranimo-about-section ul {
  margin: 0;
  padding-left: 18px;
}

.jiranimo-about-section li {
  margin-bottom: 6px;
  color: #344563;
}

.jiranimo-about-section code {
  background: #f4f5f7;
  padding: 1px 5px;
  border-radius: 3px;
  font-family: 'SFMono-Regular', Consolas, monospace;
  font-size: 12px;
}

.jiranimo-about-modal kbd {
  display: inline-block;
